insert into public.questions (pack_id, prompt, option_a, option_b, option_c, option_d, correct_option, difficulty)
select pack_id, prompt, option_a, option_b, option_c, option_d, correct_option, difficulty
from seed_questions seed
where not exists (
  select 1
  from public.questions existing
  where existing.pack_id = seed.pack_id
    and lower(existing.prompt) = lower(seed.prompt)
);
